<!doctype html><html><head><meta charset="utf-8"><title>{{ $invoice->invoice_number }}</title><style>body{font-family:Arial,sans-serif;color:#111;margin:30px}.top{display:flex;justify-content:space-between;border-bottom:2px solid #111;padding-bottom:15px}.box{margin-top:20px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:20px}table{width:100%;border-collapse:collapse;margin-top:15px}th,td{border:1px solid #ddd;padding:8px;text-align:left}th{background:#f3f4f6}.right{text-align:right}.btn{padding:8px 14px;border:1px solid #111;background:white;cursor:pointer}@media print{.no-print{display:none}}</style></head><body><button class="btn no-print" onclick="window.print()">Print</button><div class="top"><div><h1>Invoice</h1><p>{{ $invoice->invoice_number }}</p></div><div class="right"><p>Date: {{ optional($invoice->invoice_date)->format('d M Y') }}</p><p>Status: {{ $invoice->invoice_status }}</p></div></div><div class="grid box"><div><h3>Shop</h3><p>{{ $invoice->shop_name }}</p><p>{{ $invoice->shop_mobile }}</p><p>{{ $invoice->shop_address }}</p></div><div><h3>Customer</h3><p>{{ $invoice->customer_name }}</p><p>{{ $invoice->customer_mobile }}</p><p>{{ $invoice->billing_address }}</p></div></div><table><thead><tr><th>Product</th><th>SKU</th><th>Qty</th><th>Price</th><th>Total</th></tr></thead><tbody>@foreach($invoice->items as $item)<tr><td>{{ $item->product_name }}</td><td>{{ $item->product_sku }}</td><td>{{ $item->quantity }}</td><td>Rs. {{ number_format($item->price,2) }}</td><td>Rs. {{ number_format($item->total,2) }}</td></tr>@endforeach</tbody></table><div class="box right"><p>Subtotal: Rs. {{ number_format($invoice->subtotal,2) }}</p><p>Discount: Rs. {{ number_format($invoice->discount_amount,2) }}</p><p>Tax: Rs. {{ number_format($invoice->tax_amount,2) }}</p><p>Delivery: Rs. {{ number_format($invoice->delivery_charge,2) }}</p><h3>Total: Rs. {{ number_format($invoice->total_amount,2) }}</h3><p>Paid: Rs. {{ number_format($invoice->paid_amount,2) }}</p><p>Due: Rs. {{ number_format($invoice->due_amount,2) }}</p></div><div class="box"><p><strong>Notes:</strong> {{ $invoice->notes }}</p><p><strong>Terms:</strong> {{ $invoice->terms }}</p></div></body></html>
